const express = require('express');
const Redis = require('ioredis');

const app = express();
app.use(express.json());

const redis = new Redis({
  host: 'localhost',
  port: 6379,
});

function validatePattern(pattern) {
  return /^[a-zA-Z0-9\*]+$/.test(pattern);
}

function executeCommand(command, args) {
  if (!validatePattern(command)) {
    throw new Error('Invalid command');
  }
  const redisClient = new Redis({
    host: 'localhost',
    port: 6379,
  });
  return redisClient.exec([command, ...args]);
}

app.post('/search', (req, res) => {
  const pattern = req.body.pattern;
  if (!validatePattern(pattern)) {
    res.status(400).send('Invalid search pattern');
    return;
  }
  redis.keys(pattern, (err, keys) => {
    if (err) {
      console.error(err);
      res.status(500).send('Error searching Redis database');
    } else {
      res.json(keys);
    }
  });
});

app.post('/execute', (req, res) => {
  const command = req.body.command;
  const args = req.body.args || [];
  try {
    const result = executeCommand(command, args);
    if (result && result[0] === 'OK') {
      res.json({ message: `Executed command successfully` });
    } else {
      res.status(500).send('Error executing Redis command');
    }
  } catch (err) {
    console.error(err);
    res.status(500).send('Error executing Redis command');
  }
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});